INSERT INTO historia (numero_pregunta, preguntas, respuesta_a, respuesta_b, pregunta_siguiente_a, pregunta_siguiente_b) VALUES
(1, '[Edad: 0 años] Es el tradicional ritual de tu primer cumpleaños (Zha Zhou / Doljabi). Sobre una manta roja, tus padres han colocado objetos para adivinar tu futuro bajo la atenta mirada de tus ancestros. ¿Qué agarras primero?', 'Bolígrafo de caligrafía', 'Billete falso', 2, 3),
(2, '[Edad: 2 años] La fiebre te mantiene despierto en la noche. Para equilibrar tu "Qi", tu sabia abuela te prepara una infusión de medicina tradicional china, humeante y extremadamente amarga. ¿Qué haces?', 'Te lo bebes', 'Lo escupes', 4, 5),
(3, '[Edad: 2 años] Jugando en el salón, rompes una imitación de un jarrón de la dinastía Ming. En una cultura donde "dar la cara" (Mianzi) y la disciplina estricta son la norma, el castigo es inminente.', 'Culpas al gato', 'Asumes el golpe de la escoba', 6, 7),
(4, '[Edad: 3 años] Es el Festival de Primavera (Año Nuevo Lunar). Los petardos suenan fuera y tu tío te entrega un "Hongbao" (sobre rojo) lleno de billetes nuevos para la buena fortuna. Mamá se acerca sonriendo...', 'Se lo das a mamá para que lo guarde', 'Lo escondes en tu almohada', 8, 9),
(5, '[Edad: 4 años] En tu primer día de guardería, abres tu fiambrera (Bento/Dosirak) preparada con amor por tu madre, pero un niño más grande te roba tu comida. El instinto de supervivencia aflora.', 'Lloras al profesor', 'Le muerdes el brazo', 10, 11),
(6, '[Edad: 5 años] Es la hora de cenar y tus abuelos tienen el control de la televisión. Te obligan a ver interminables dramas históricos (Sageuk) sobre traiciones en el palacio imperial del siglo XV.', 'Prestas atención a las intrigas', 'Te duermes', 12, 13),
(7, '[Edad: 6 años] Empieza la implacable escuela primaria. El profesor de caligrafía te golpea los nudillos con una regla de bambú porque tu escritura de caracteres (Kanji/Hanja) carece de alma y precisión.', 'Practicas 5 horas hasta sangrar', 'Falsificas firmas', 14, 15),
(8, '[Edad: 7 años] La peor traición de la infancia asiática se ha consumado: descubres que tu madre usó el dinero de tu Hongbao "guardado" para pagar la factura de la luz. ¿Cómo reaccionas?', 'Aceptas la piedad filial', 'Empiezas a robarle cambio', 16, 17),
(9, '[Edad: 8 años] Estás en una academia extraescolar aprendiendo a usar el Soroban (ábaco tradicional). El profesor dicta números a la velocidad del rayo y te estás quedando muy atrás.', 'Te esfuerzas al máximo', 'Usas una calculadora a escondidas', 18, 19),
(10, '[Edad: 9 años] Traes a casa un examen de matemáticas con un 98 sobre 100. En lugar de alegrarse, tu madre cruza los brazos y te mira con una frialdad gélida, preguntando dónde están los 2 puntos que faltan.', 'Pides perdón de rodillas', 'Dices que el examen estaba mal', 20, 21),
(11, '[Edad: 10 años] En el patio, una pandilla que emula a las Tríadas locales te ofrece protección a cambio de que les ayudes a extorsionar cromos raros de anime a los alumnos de primer curso.', 'Aceptas el poder', 'Los delatas', 22, 23),
(12, '[Edad: 10 años] Volviendo a casa por los callejones estrechos (Hutong), encuentras un manga para adultos tirado en el suelo, una verdadera rareza en tu conservador vecindario.', 'Lo vendes en la escuela', 'Lo tiras por respeto', 24, 25),
(13, '[Edad: 11 años] Llega el torneo nacional de piano. Tu peor enemigo, el mítico "Hijo de la amiga de tu madre" (siempre perfecto y estudioso), acaba de tocar una pieza impecable de Chopin.', 'Estudias violín para superarlo', 'Saboteas su piano con salsa de soja', 26, 27),
(14, '[Edad: 12 años] Has deshonrado a la familia por no sacar la máxima nota y te han castigado sin cenar. Tu estómago ruge mientras hueles el estofado de cerdo que cocina tu abuela.', 'Ayunas y meditas', 'Te escapas por la ventana a comer fideos', 28, 29),
(15, '[Edad: 12 años] Te has perdido en la zona de neones del distrito rojo y una pandilla de delincuentes juveniles (Yankiis/Iljin) en motocicletas ruidosas te acorrala contra un callejón sin salida.', 'Huyes corriendo', 'Les tiras tu mochila y te unes', 30, 31),
(16, '[Edad: 13 años] La presión del "Infierno de los Exámenes" comienza. Te envían a un Hagwon (Academia intensiva) hasta las 11 de la noche todos los días. Estás agotado física y mentalmente.', 'Aguantas estoicamente', 'Te fugas a un PC Bang a jugar', 32, 33),
(17, '[Edad: 14 años] En la rígida sociedad estudiantil, el aspecto físico lo es todo. Tus compañeros te presionan por tu acné, diciéndote que sin la piel de cristal (Glass skin) no tendrás futuro.', 'Estudias, el físico no importa', 'Robas cosméticos coreanos caros', 34, 35),
(18, '[Edad: 15 años] Antes de los exámenes, tu madre te lleva a un templo budista en la montaña. Un monje, rodeado de incienso, dice que tienes un aura oscura y suspenderás a menos que hagas una donación.', 'Pagas la bendición', 'Confías en tu cerebro', 36, 37),
(19, '[Edad: 15 años] Desastre. El monitor del pasillo, un estudiante con delirios de dictador, te ha pillado usando una calculadora programable en el examen de física cuántica básica.', 'Sobornas al monitor', 'Confiesas y pierdes honor', 38, 39),
(20, '[Edad: 16 años] Bajo los cerezos en flor del patio del instituto, experimentas tu primer amor. El romanticismo de los dramas asiáticos te inunda, pero no tienes ni un céntimo para invitarla/o a salir.', 'Le escribes poesía clásica', 'Invitas a Bubble Tea con dinero robado', 40, 41),
(21, '[Edad: 16 años] Te enfrentas a un examen sorpresa de historia contemporánea dictado por un profesor muy apegado a la doctrina oficial del Partido. La pregunta requiere justificar un evento polémico.', 'Respondes lo oficial', 'Pones tu opinión crítica', 42, 43),
(22, '[Edad: 17 años] Tu habilidad en el cibercafé no ha pasado desapercibida. Un reclutador con traje te ofrece un contrato para ser profesional de eSports y vivir en una Gaming House en Seúl, pero debes dejar el instituto.', 'Firmas en secreto', 'Lo rechazas por los estudios', 44, 45),
(23, '[Edad: 17 años] Unos matones te esperan a la salida del colegio exigiendo el "impuesto de protección". Estás harto de vivir con miedo y decides que es hora de tomar medidas drásticas.', 'Aprendes artes marciales (Wushu)', 'Llevas una navaja', 46, 47),
(24, '[Edad: 18 años] Es la víspera del Gaokao / Suneung, el examen de acceso universitario que decidirá el 100% de tu futuro laboral y social. La tensión es tan densa que podrías cortarla con una katana.', 'Tomas 5 latas de ginseng', 'Duermes 8 horas', 48, 49),
(25, '[Edad: 18 años] Día del examen. El silencio en el pabellón deportivo es sepulcral. Abres el cuadernillo y tu mente se queda completamente en blanco. El pánico se apodera de tu respiración.', 'Copias del de al lado', 'Respiras y te enfocas', 50, 51),
(26, '[Edad: 18 años] Las notas han salido: has suspendido el acceso por 1 miserable punto. La vergüenza cae sobre tu linaje y tus familiares murmuran a tus espaldas en la cena. ¿Cómo salvas la situación?', 'Año de aislamiento (Rōnin)', 'Falsificas la nota de admisión', 52, 53),
(27, '[Edad: 18 años] Llegando tarde al examen, tu pequeña scooter resbala en el asfalto mojado. Tienes una brecha en la frente sangrando, pero la campana está a punto de sonar.', 'Vas al hospital', 'Ignoras la herida para llegar al examen', 54, 197),
(28, '[Edad: 18 años] Has aprobado, pero tu familia está en la ruina y no puede pagar la extorsiva matrícula de la universidad de élite. Necesitas dinero rápido, y en este barrio hay dos formas de conseguirlo.', 'Pides préstamo a un banco', 'Pides dinero a la Tríada', 55, 56),
(29, '[Edad: 18 años] El estrés te ha llevado a fumar a escondidas en el tejado del instituto. El estricto director, conocido por sus castigos corporales, te sorprende con el cigarrillo en la mano.', 'Pides perdón al director', 'Le echas el humo a la cara', 57, 58),
(30, '[Edad: 18 años] ¡Milagro académico! Has sacado la puntuación perfecta. Tu foto está en los periódicos locales y el alcalde felicita a tus padres. El mundo está a tus pies.', 'Vas a universidad top', 'Te relajas y vas a discotecas', 59, 60),
(31, '[Edad: 19 años] Es tu primer día en el campus universitario. Para integrarte en la rígida jerarquía social (Sunbae/Hubae), debes unirte a un club. ¿Eliges el prestigio o la pura fiesta descontrolada?', 'Te unes al club de debate', 'Fraternidad de bebedores de Soju', 61, 62),
(32, '[Edad: 20 años] Época de exámenes finales en la universidad de élite. Un estudiante de medicina de último año te ofrece unas "píldoras de concentración" no registradas que te quitarán el sueño tres días.', 'Las tomas para los exámenes', 'Las tiras a la basura', 63, 64),
(33, '[Edad: 20 años] Estás compitiendo en un torneo amateur de League of Legends con un premio en metálico inmenso. En la partida final, fallas tu combo definitivo y tu equipo pierde.', 'Te retiras y estudias', 'Rompes el teclado y peleas', 65, 66),
(34, '[Edad: 21 años] Para pagarte la universidad, trabajas en el turno de noche de un Konbini (tienda 24 horas). Entra un hombre desesperado con el rostro cubierto empuñando un cuchillo de cocina.', 'Das la caja fuerte', 'Atacas con un paraguas', 67, 191),
(35, '[Edad: 21 años] Las cámaras de seguridad te han grabado robando costosos cosméticos coreanos de baba de caracol. El guardia de seguridad te agarra del brazo antes de que salgas por la puerta.', 'Pagas vaciando ahorros', 'Huyes por los callejones', 68, 69),
(36, '[Edad: 22 años] Día de entrevistas para entrar a un Chaebol/Zaibatsu (una de las megacorporaciones que controlan el país). Llevas un traje negro idéntico al de otros 500 candidatos. Te hacen pasar.', 'Reverencias de 90 grados', 'Eres arrogante pero brillante', 70, 71),
(37, '[Edad: 22 años] Un cazatalentos en el metro te frena. Ve en ti el potencial visual para ser un "Idol" de K-Pop, pero las agencias imponen dietas extremas y contratos draconianos de 10 años.', 'Contrato esclavo 10 años', 'Indie en la calle', 72, 73),
(38, '[Edad: 23 años] Eres el oficinista de menor rango (Maknae). Son las 9 de la noche y has terminado, pero por pura etiqueta social no puedes irte hasta que tu jefe se levante de su silla... y no parece querer irse.', 'Trabajas 14 horas', 'Gritas y dimites', 74, 75),
(39, '[Edad: 23 años] El prestamista de la mafia local, con tatuajes de dragones asomando por su camisa, aparece en tu puerta. Te exige el dinero prestado con unos intereses abusivos.', 'Consigues segundo trabajo', 'Haces de mula para pagar', 76, 77),
(40, '[Edad: 24 años] Es viernes. Tu equipo entero es forzado a ir a un Nomikai/Hweshik (cena de borrachera obligatoria con el jefe). El director no para de servirte vasitos de Soju ardiente y no puedes decir que no.', 'Bebes hasta el colapso', 'Lo tiras a una planta', 78, 79),
(41, '[Edad: 24 años] La presión del estatus ataca tu corazón: tu pareja te abandona, alegando fríamente que no ganas suficiente dinero al mes para asegurar un futuro en la clase media alta.', 'Gimnasio y dinero', 'Te deprimes y bebes', 80, 81),
(42, '[Edad: 25 años] El departamento de Recursos Humanos de tu corporación ha estado investigando y ha descubierto que el sello de tu diploma universitario es una hábil falsificación hecha en Photoshop.', 'Suplicas clemencia', 'Chantaje al de RRHH', 82, 83),
(43, '[Edad: 25 años] La vida de oficinista te asqueó. Con tus ahorros montas un pequeño puesto callejero de pollo frito, el destino final de muchos trabajadores exhaustos. Los márgenes de beneficio son crueles.', 'Usas aceite limpio', 'Usas Gutter Oil para ahorrar', 84, 193),
(44, '[Edad: 25 años] Te han despedido por reducción de plantilla. El deshonor social es inmenso y tus padres te miran con decepción. Tienes tu liquidación en el bolsillo. ¿Qué haces con el capital?', 'Opositas a funcionario', 'Inviertes en criptomonedas', 85, 45),
(45, '[Edad: 26 años] El mercado de criptomonedas asiático está colapsando en vivo por un hackeo en un exchange de Tokio. Tienes invertido todo tu dinero y solo queda 1 minuto antes de que el valor llegue a cero absoluto.', 'Retiras a tiempo (Ruta Buena)', 'Apalancas x100 y pierdes (Ruta Mala)', 90, 120),
(46, '[Edad: 27 años] Tu tía, empeñada en salvar tu honor, ha organizado un "Omiai/Seon" (cita a ciegas arreglada) con el hijo/a del dueño de un hospital. Tu destino corporativo/familiar depende de si asistes o te rebelas.', 'Vas formal (Ruta Buena)', 'Te embriagas en bar Yakuza (Ruta Mala)', 91, 121),
(47, '[Edad: 28 años] Tras meses de trabajo esclavo, el gerente de tu sección ha presentado tu proyecto estrella al Director General como si fuera suyo, llevándose todos los elogios y el bono económico.', 'Tragas bilis (Ruta Buena)', 'Le rompes el coche (Ruta Mala)', 92, 122),
(48, '[Edad: 29 años] Para mantener el ritmo de 80 horas semanales de trabajo, has mezclado demasiadas bebidas de ginseng rojo, taurina y café expreso. Tu corazón palpita dolorosamente fuera de ritmo.', 'Vas a urgencias (Ruta Buena)', 'Ignoras al médico', 93, 199),
(49, '[Edad: 30 años] Las altas esferas de tu empresa (o del partido local) han notado tu ambición. Te ofrecen entrar en su círculo de élite corporativa, pero te exigen lealtad absoluta y hacer la vista gorda ante sus negocios sucios.', 'Aceptas lealtad (Ruta Buena)', 'Rechazas por principios (Ruta Mala)', 94, 123),
(50, '[Edad: 30 años] Los matones de los cobradores de deudas te han acorralado en los muelles de la ciudad bajo la lluvia. Tienes dos opciones para evitar acabar en el fondo del mar con zapatos de cemento.', 'Carguero a Japón (Ruta Mala)', 'Confiesas a la policía (Ruta Buena)', 124, 95),
(51, '[Edad: 20 años] En la universidad, un venerable y anciano profesor cuestiona públicamente tu ensayo sobre ética confuciana. En esta cultura, llevarle la contraria al maestro es un tabú severo.', 'Rehaces el trabajo', 'Le debates públicamente', 45, 46),
(52, '[Edad: 20 años] Para castigarte y prepararte para el siguiente año de exámenes, tu familia te ha enviado a un templo remoto en la montaña a estudiar en régimen de aislamiento monástico.', 'Mantienes la cordura', 'Hablas con los árboles', 47, 48),
(53, '[Edad: 20 años] Tu título falso ha sido aceptado por el sistema de la megacorporación. Ahora cobras un sueldo de directivo junior, pero el síndrome del impostor y la paranoia te persiguen.', 'Mantienes un perfil bajo', 'Alardeas en redes sociales', 49, 50),
(54, '[Edad: 20 años] Recuperándote en el hospital, entablas conversación con el cirujano jefe. Descubres que tiene contactos con el mercado negro, abriendo un abanico de posibilidades éticamente dudosas.', 'Le pides consejo de carrera', 'Le robas medicinas', 90, 120),
(55, '[Edad: 20 años] El rígido banco estatal te aprueba el crédito universitario gracias al aval de un familiar. Tienes en tu cuenta millones de wones/yenes listos para ser usados.', 'Pagas la universidad', 'Lo gastas en ropa de marca', 90, 120),
(56, '[Edad: 20 años] El líder de la pandilla callejera pone un maletín de aluminio lleno de billetes en tus manos. Te dice que este favor "se pagará con sangre si es necesario".', 'Pagas la matrícula', 'Huyes con el dinero', 120, 192),
(57, '[Edad: 20 años] El director te hace una severa reverencia inversa y, sorpresivamente, te perdona la expulsión tras la intervención de tus padres, quienes donaron un nuevo proyector al colegio.', 'Estudias más', 'Vuelves a fumar', 90, 120),
(58, '[Edad: 20 años] Has sido expulsado con deshonor. En el tablón de anuncios está tu nombre tachado en rojo. Tus opciones de entrar al sistema corporativo se han desvanecido para siempre.', 'Buscas trabajo manual', 'Te unes a pandillas', 120, 123),
(59, '[Edad: 20 años] Has llegado a la Universidad Top de la capital. Estás rodeado de herederos de corporaciones y genios nacionales. La presión es aplastante.', 'Estudias en la biblioteca', 'Vas a fiestas exclusivas', 90, 121),
(60, '[Edad: 20 años] Atrapado por los destellos del distrito de ocio de Gangnam/Roppongi, empiezas a faltar a clase para sumergirte en la vida nocturna y los clubes VIP.', 'Dejas de ir', 'Te haces DJ', 90, 120),
(61, '[Edad: 19 años] Con elocuencia implacable, humillas a tu rival y ganas el campeonato nacional de debate. Tu labia te abre las puertas a casi cualquier manipulación burocrática.', 'Pides beca', 'Te vuelves arrogante', 90, 46),
(62, '[Edad: 19 años] El infame rito de iniciación de tu fraternidad universitaria te ha provocado un coma etílico tras obligarte a beber un embudo de licor de arroz de 40 grados.', 'Vas a rehabilitación', 'Sigues bebiendo', 90, 199),
(63, '[Edad: 20 años] Las "pastillas para estudiar" que compraste en el callejón están destrozando tus receptores de dopamina. Si no las tomas, no puedes ni levantar el bolígrafo.', 'Buscas ayuda', 'Compras más en la calle', 90, 120),
(64, '[Edad: 20 años] Te has negado a hacer trampas, pero el rigor de la universidad asiática es brutal. Has suspendido el año y tu familia se niega a mirarte a los ojos en la cena.', 'Estudias en verano', 'Falsificas las notas', 90, 120),
(65, '[Edad: 20 años] Abandonaste tu sueño gamer y te recluiste en la biblioteca. Tus ojos están rojos, tu postura encorvada, pero el examen final para ser funcionario está sobre tu mesa.', 'Apruebas', 'Te duermes en el examen', 90, 48),
(66, '[Edad: 20 años] La furia gamer te dominó. Destrozaste el valioso equipo del PC Bang (cibercafé). El dueño, ex-miembro de una pandilla, bloquea la salida con un bate de béisbol.', 'Pagas los daños', 'Golpeas al dueño del PC Bang', 90, 120),
(67, '[Edad: 21 años] Tu cobardía (o prudencia) ante el atracador del Konbini hizo que tu jefe, un hombre obsesionado con las ganancias, te despida por no defender "el honor de la tienda".', 'Buscas otro trabajo', 'Robas mercancía antes de irte', 90, 120),
(68, '[Edad: 21 años] Pagar la multa del robo de cosméticos te ha dejado con la cuenta bancaria a cero. Quedan 30 días para fin de mes y el hambre aprieta en tu minúsculo apartamento tipo caja de zapatos.', 'Comes ramen un mes', 'Pides a usureros', 90, 120),
(69, '[Edad: 21 años] Corres por los intrincados callejones húmedos de neón huyendo de la seguridad. Escuchas las sirenas acercándose rápidamente. Debes tomar una decisión física arriesgada.', 'Te escondes en la basura', 'Saltas un muro con pinchos', 120, 195),
(70, '[Edad: 22 años] El conglomerado te ha aceptado. Ahora eres un "Salaryman", un engranaje en la máquina corporativa que mueve la economía del país. Te dan tu tarjeta identificativa.', 'Eres sumiso', 'Buscas ascender rápido', 90, 47),
(71, '[Edad: 22 años] El Chaebol te rechaza alegando que "el clavo que sobresale recibe el martillazo". Tu actitud individualista no encaja en su cultura gregaria. Debes buscarte la vida fuera del sistema.', 'Montas tu empresa', 'Haces estafas online', 90, 120),
(72, '[Edad: 22 años] Estás atrapado en un contrato de K-Pop. Duermes 3 horas al día, tienes prohibido tener pareja y tu peso es monitorizado cada mañana. Tu salud mental pende de un hilo.', 'Sonríes a las cámaras', 'Te revelas en directo', 90, 120),
(73, '[Edad: 22 años] Elegiste el camino del músico callejero en el barrio bohemio de Hongdae. La libertad artística es hermosa, pero el frío del invierno asiático cala hasta los huesos.', 'Ganas fans', 'Mueres de hambre', 90, 120),
(74, '[Edad: 23 años] La temida cultura del exceso de trabajo está minando tu cuerpo. Tu piel es gris, tu vista se nubla y sufres mareos constantes. El doctor de la empresa te sugiere "esforzarte más".', 'Tomas vitaminas', 'Tomas sustancias ilegales', 90, 120),
(75, '[Edad: 23 años] Eres un desempleado en una sociedad que juzga el valor humano por la tarjeta de visita corporativa. El estigma es insoportable; tus antiguos compañeros cruzan de acera al verte.', 'Buscas trabajo', 'Te unes a la mafia', 90, 120),
(76, '[Edad: 23 años] Para pagar a los usureros, trabajas de oficinista de día y limpiador de baños de karaoke de noche. Tu cuerpo lleva 72 horas sin tocar un colchón.', 'Pagas la deuda', 'Colapsas de cansancio', 90, 190),
(77, '[Edad: 23 años] Las Tríadas te han usado como mula de contrabando transfronterizo. Llevas un paquete pegado al pecho sudando frío mientras el oficial de aduanas te mira fijamente a los ojos.', 'Tienes éxito', 'Te pilla la aduana', 120, 198),
(78, '[Edad: 24 años] Tras la cena de empresa, te despiertas tirado sobre cartones en una estación de metro de Tokio, abrazado a tu maletín. Tienes la camisa manchada de vómito y pierdes tu tren bala.', 'Vas a casa', 'Sigues bebiendo', 90, 120),
(79, '[Edad: 24 años] El jefe de departamento se percata de que has desechado su ofrenda de licor, lo cual es un insulto gravísimo a su autoridad jerárquica. El restaurante se queda en absoluto silencio.', 'Pides perdón', 'Le insultas', 90, 120),
(80, '[Edad: 24 años] Canalizas el desamor hacia el levantamiento de pesas. Te conviertes en una montaña de músculos, un perfil muy intimidante en una sociedad de oficinistas trajeados.', 'Consigues mejor trabajo', 'Te haces matón', 90, 120),
(81, '[Edad: 24 años] El dolor de la ruptura y el rechazo social te arrastran. Buscas consuelo en las ruidosas y humeantes salas de Pachinko o casinos flotantes, donde el tiempo (y el dinero) desaparecen.', 'Vas a terapia', 'Vas al casino', 90, 120),
(82, '[Edad: 25 años] Milagrosamente, la junta directiva decide hacer la vista gorda sobre tu título falso gracias a tus excelentes métricas de ventas. Pero te advierten que le debes la vida a la empresa.', 'Trabajas duro', 'Vuelves a mentir', 90, 120),
(83, '[Edad: 25 años] Usando técnicas sucias, has extorsionado al jefe de Recursos Humanos amenazando con revelar su malversación de fondos. El poder cambia de bando, pero has creado un enemigo letal.', 'Consigues aumento', 'Te envían sicarios', 120, 192),
(84, '[Edad: 25 años] ¡Un éxito arrollador! Un popular influencer de comida hizo una reseña de tu pollo frito coreano y ahora hay colas de 3 horas dando la vuelta a la manzana en tu pequeño local.', 'Abres franquicia', 'Vendes la receta', 90, 45),
(85, '[Edad: 25 años] Tras tu despido, te encierras a memorizar miles de páginas de leyes para el examen de funcionario estatal, buscando la codiciada seguridad de la "taza de arroz de hierro" (empleo vitalicio).', 'Apruebas', 'Suspendes y enloqueces', 90, 120),
(86, '[Edad: 25 años] El token digital de los perritos en el que invertiste tus ahorros acaba de subir un 40,000% tras el tweet de un multimillonario excéntrico. Tienes una pequeña fortuna flotando en tu móvil.', 'Vendes', 'Haces HODL', 90, 45),
(87, '[Edad: 25 años] El sentido del deber familiar te acorrala: un primo lejano ha fracasado en su negocio y, por la presión de los tíos, te exigen que le "prestes" tus ahorros sin contrato.', 'Le prestas', 'Te niegas', 90, 120),
(88, '[Edad: 25 años] Un antiguo amigo de la secundaria, ahora vestido con un Rolex deslumbrante, te invita a un seminario en un hotel de lujo para presentarte una "oportunidad de negocio piramidal ineludible".', 'Rechazas', 'Entras de cabeza', 90, 120),
(89, '[Edad: 25 años] La tragedia ataca tu vida diaria. Un tifón inunda tu apartamento en el sótano (tipo Banjiha). El agua contaminada ha destruido todas tus posesiones terrenales.', 'Pagas el seguro', 'Buscas culpables a golpes', 90, 120),
(90, '[Edad: 31 años] Alcanzada la estabilidad económica, la presión de tus padres por continuar el linaje es implacable. Su orgullo exige una boda monumental con cientos de invitados para exhibir estatus.', 'Pagas la dote altísima', 'Te casas por lo civil en secreto', 91, 92),
(91, '[Edad: 32 años] Recién casado, la presión salta al siguiente nivel: continuar el apellido familiar. Tu cónyuge sigue las expectativas sociales y exige empezar a tener descendencia de inmediato.', 'Aceptas tener hijos', 'Adoptas un perro Shiba Inu', 93, 94),
(92, '[Edad: 33 años] La burbuja inmobiliaria estalla. El moderno apartamento por el que te endeudaste pierde la mitad de su valor, pero el banco exige los mismos pagos asfixiantes mes a mes.', 'Sigues pagando hipoteca 30 años', 'Dejas de pagar y huyes', 95, 125),
(93, '[Edad: 34 años] En nombre de la "armonía familiar", tu suegra se ha mudado a tu casa. Cada noche, inspecciona la cocina y critica con mordacidad que el arroz está demasiado húmedo o muy seco.', 'Compras arrocera IA $500', 'Guerra pasivo-agresiva', 96, 97),
(94, '[Edad: 36 años] Has sido ascendido a Gerente de División. El problema es que para cumplir los inhumanos objetivos de la empresa corporativa, estás aplastando la salud mental de tus subordinados, que te odian.', 'Invitas a karaoke', 'Gobiernas con puño de hierro', 98, 99),
(95, '[Edad: 38 años] Tu hijo llega a casa con un 60/100 en el examen simulado del Gaokao. El futuro de su estatus social corre peligro y tu familia política te acusa de ser un mal padre.', 'Pagas academias caras', 'Le dejas ser feliz (Sociedad juzga)', 100, 101),
(96, '[Edad: 40 años] La revisión médica anual (Ningen Dock) revela que tus triglicéridos están destruyendo tus arterias debido a tanto ramen instantáneo, cerdo agridulce y estrés corporativo.', 'Bebes agua caliente en termo', 'Sigues comiendo panceta', 102, 103),
(97, '[Edad: 42 años] Has logrado todo lo que la sociedad exige: dinero, piso, familia y estatus. Y, sin embargo, parado en tu oficina de cristal en el piso 40, sientes un vacío espiritual aterrador.', 'Compras templo budista', 'Vas a casinos ilegales', 104, 126),
(98, '[Edad: 45 años] La revolución tecnológica sacude tu oficina. Los nuevos empleados de la "Generación MZ" utilizan Inteligencia Artificial para hacer en 10 minutos lo que a ti te cuesta 4 horas.', 'Aprendes a usar IA', 'Obligas a hacer fotocopias', 105, 106),
(99, '[Edad: 48 años] Descubres accidentalmente que la junta directiva de tu megacorporación está evadiendo impuestos por valor de cientos de millones a través de paraísos fiscales. Tienen los libros listos para la trituradora.', 'Destruyes documentos', 'Eres informante (Whistleblower)', 107, 108),
(100, '[Edad: 50 años] ¡Gloria familiar! Tu hijo ha sido admitido en la Universidad Nacional de Seúl / Pekín / Tokio. Es el momento de ofrecer un fastuoso banquete para presumir ante parientes y rivales.', 'Aleta de tiburón sintética', 'Mariscos vivos carísimos', 109, 110),
(101, '[Edad: 52 años] Las responsabilidades del puesto directivo y el miedo a perder el estatus te provocan ataques de pánico nocturnos. Sientes que el peso de tu familia recae como una losa sobre tu pecho.', 'Retiro espiritual', 'Automedicación secreta', 111, 130),
(102, '[Edad: 55 años] La empresa te presiona para aceptar la "Jubilación Honorífica Anticipada" a los 55 años, para dejar paso a la juventud. Tu familia espera que pases a ser un abuelo/a que cuide niños gratis.', 'Aceptas para cuidar nietos', 'Te niegas', 112, 113),
(103, '[Edad: 58 años] Te diagnostican Síndrome de Fatiga Crónica severa. El médico, con rostro sombrío, te indica que si sigues el ritmo actual, tu esperanza de vida no superará el lustro.', 'Renuncias y descansas', 'Sigues trabajando 14 horas', 114, 190),
(104, '[Edad: 60 años] Paseando por un jardín zen, un monje errante se cruza en tu camino y te dice: "Tu cuenta bancaria está llena, pero tu Karma está en números rojos". Te insta a desprenderte de lo material.', 'Donas tu fortuna', 'Ignoras al monje', 115, 116),
(105, '[Edad: 40 años] Escándalo familiar: tu hija, que estudió en el extranjero, vuelve anunciando que va a casarse con un extranjero que no entiende ni una palabra de vuestra cultura, idiomas ni tradiciones de reverencia.', 'Lo aceptas', 'Lo repudias', 117, 118),
(106, '[Edad: 46 años] La economía colapsa y la sede central exige un "sacrificio". Te ordenan despedir al 50% de tu leal equipo que lleva trabajando a tu lado 15 años, o tu propia cabeza rodará.', 'Salvas a tu equipo', 'Te salvas a ti mismo', 119, 161),
(107, '[Edad: 51 años] Gracias a una gran donación cívica, el alcalde local decide otorgarte una codiciada Medalla al Mérito Cívico en un evento televisado lleno de pompa y formalidades.', 'Aceptas humilde', 'Das discurso arrogante', 161, 162),
(108, '[Edad: 49 años] Filtraste la corrupción corporativa a la prensa. Ahora recibes amenazas de muerte anónimas, motoristas merodean tu casa y tus cuentas bancarias han sido misteriosamente congeladas.', 'Pides protección', 'Huyes del país', 161, 160),
(109, '[Edad: 51 años] El banquete por tu hijo es la envidia del distrito. Tus rivales (incluida la insufrible "amiga de tu madre") se inclinan ante ti reconociendo tu triunfo social absoluto. Eres el rey de la piedad filial.', 'Te relajas', 'Gastas más en lujos', 161, 162),
(110, '[Edad: 51 años] Para pagar los lujos y el estatus exigidos en el banquete, te has endeudado en secreto a espaldas de tu cónyuge. La presión por mantener la farsa del millonario te asfixia.', 'Trabajas más', 'Robas a la empresa', 161, 129),
(111, '[Edad: 53 años] Regresas del retiro monástico en las montañas limpio y con una nueva perspectiva taoísta de la vida corporativa. El dinero ya no te controla, lideras con compasión.', 'Eres mejor jefe', 'Dejas el trabajo', 161, 161),
(112, '[Edad: 56 años] Tus domingos están llenos del bullicio de tus nietos corriendo por la casa tradicional. Eres el patriarca/matriarca respetado de una familia modélica, la envidia de la sociedad.', 'Les compras juguetes', 'Les enseñas caligrafía', 161, 161),
(113, '[Edad: 59 años] Ignorando las alarmas de tu cuerpo, sufres un espasmo cardíaco agudo en mitad de una presentación clave. Caaes desplomado agarrándote el pecho sobre el proyector.', 'Te jubilas', 'Sigues (locura)', 161, 190),
(114, '[Edad: 61 años] Libre de las cadenas de la oficina, encuentras la paz en las artes milenarias. El sonido del pincel sobre el papel de arroz o las tijeras podando bonsáis marcan tus tranquilas tardes.', 'Jardinería', 'Pintura tradicional', 161, 161),
(115, '[Edad: 61 años] No tienes la fortuna de los grandes Chaeboles, pero tu familia te adora y el monje local te considera un maestro de la paz interior. La sencillez ha sido tu mayor lujo.', 'Meditas', 'Ayudas en el templo', 161, 161),
(116, '[Edad: 43 años] Presumes de estatus comprando valiosas cerámicas de Celadón y rollos de caligrafía antigua, llenando tu casa de reliquias para que tus invitados admiren tu elevado gusto cultural.', 'Ganas prestigio', 'Pierdes dinero', 161, 161),
(117, '[Edad: 41 años] Pese a las miradas críticas de los ancianos del pueblo, bendices el matrimonio de tu hija. La fusión de culturas en el banquete resulta ser una fiesta legendaria y alegre.', 'Bailas en la boda', 'Te quedas sentado', 161, 161),
(118, '[Edad: 41 años] Impusiste tu autoridad patriarcal/matriarcal y repudiaste a su prometido extranjero. Para salvar tu orgullo cultural, perdiste a tu hija, quien cortó toda relación contigo.', 'Pides perdón', 'Mantienes el orgullo', 161, 162),
(119, '[Edad: 47 años] Te negaste a hacer de verdugo corporativo y salvaste a tu equipo asumiendo toda la culpa. Fuiste despedido con deshonor por los jefes, pero tus subordinados te rinden una reverencia llorando.', 'Lloras de emoción', 'Sonríes', 161, 161),
(120, '[Edad: 31 años] Te has adentrado en el oscuro inframundo. La Tríada local / Yakuza te ha convocado a un almacén lúgubre. Debes un millón y el jefe afila un cuchillo de trinchar frente a ti.', 'Vendes un riñón en un callejón', 'Robas un coche de lujo', 128, 129),
(121, '[Edad: 32 años] Eres un adicto a los antros clandestinos llenos de humo. Sentado en la mesa de Mahjong de altas apuestas, la tensión es brutal: tu deuda supera tu capacidad de pago y es tu turno de mover ficha.', 'Haces trampas con la manga', 'Apuestas tu propia libertad', 130, 131),
(122, '[Edad: 33 años] Lo has perdido todo. Eres un "Refugiado de los Cibercafés", vagando por las frías calles y durmiendo en cubículos de 1 metro cuadrado frente a monitores polvorientos. El hambre es insoportable.', 'Robas comida de supermercados', 'Pides limosna con cartel falso', 132, 133),
(123, '[Edad: 35 años] La mafia ve en tu desesperación un recurso útil. Te reclutan como "recolector", dándote un bate de béisbol de aluminio envuelto en alambre de espino para cobrar a los pobres infelices.', 'Rompes piernas a deudores', 'Te niegas a usar violencia', 134, 135),
(124, '[Edad: 38 años] Huyendo de la ley, consigues trabajo bajo una identidad falsa en un destartalado barco de pesca ilegal en el Mar de Bering. El capitán trata a la tripulación como esclavos descartables.', 'Lideras motín contra el capitán', 'Te escondes en la bodega', 136, 137),
(125, '[Edad: 40 años] ¡Sirenas policiales! Un escuadrón táctico de operaciones especiales (SWAT) irrumpe destrozando las puertas de la guarida donde realizas negocios clandestinos. Estás rodeado de luces estroboscópicas.', 'Escapas por alcantarillas', 'Disparas a ciegas', 138, 198),
(126, '[Edad: 42 años] Te has establecido en las profundidades de la ciudad operando un laboratorio ilegal subterráneo. Aquí el aire es tóxico y el riesgo mortal, pero el dinero sucio fluye como el agua.', 'Haces cosméticos falsos', 'Cocinas sustancias ilegales', 139, 140),
(127, '[Edad: 45 años] En un clásico giro del bajo mundo, el subjefe del sindicato del crimen te apuñala por la espalda (metafóricamente... de momento) para quedarse con tu lucrativo territorio.', 'Inicias guerra de bandas', 'Huyes rural bajo otra identidad', 141, 142),
(128, '[Edad: 48 años] El cirujano callejero que te extrajo el riñón en aquel sucio callejón usó instrumentos no esterilizados. Sufres escalofríos y fiebre extrema por una infección de sangre masiva.', 'Robas antibióticos', 'No haces nada', 143, 196),
(129, '[Edad: 50 años] Has caído. Te encuentras vistiendo el uniforme de recluso en una prisión de máxima seguridad, rodeado de asesinos tatuados y mafiosos rivales. La supervivencia en el patio es una guerra.', 'Te unes a la banda dominante', 'Te haces budista en la celda', 144, 145),
(130, '[Edad: 52 años] Cumpliste tu condena y sales por las grandes puertas de hierro de la prisión. La sociedad te margina (tus antecedentes son un tatuaje invisible) y en tus bolsillos solo tienes pelusas.', 'Vuelves a vender piratería', 'Te haces basurero municipal', 146, 147),
(131, '[Edad: 55 años] Encontraste una fortuna operando un imperio de gestión y desecho de residuos en las sombras, controlando vertederos tóxicos al margen de todas las leyes ecologistas internacionales.', 'Sobornas políticos', 'Quemas basura tóxica de noche', 148, 149),
(132, '[Edad: 58 años] Las mafias a las que traicionaste contrataron a un letal asesino a sueldo (cazarrecompensas) de la vieja escuela. Notas el destello de la mira láser de su rifle barriendo tu ventana.', 'Trampa con explosivos caseros', 'Saltas por la ventana', 150, 195),
(133, '[Edad: 60 años] Tu cordura se ha desmoronado por la vida en la calle, pero los otros indigentes ven tu locura como sabiduría. Te proclaman, en broma o en serio, el "Gran Rey de los Bajos Fondos".', 'Lideras ejército de indigentes', 'Crees ser un emperador Ming', 163, 164),
(134, '[Edad: 36 años] Tu brutalidad y eficiencia criminal te han hecho ganar un asiento en la mesa directiva del Sindicato Oscuro. Eres un Capo. Ahora, la ambición te dicta el siguiente paso en la escalera.', 'Pides más territorio', 'Traicionas al jefe', 151, 152),
(135, '[Edad: 36 años] Mostraste debilidad al no querer torturar a un deudor moroso. Para la Tríada, la debilidad se castiga. El clan entero pide que te corten un dedo (Yubitsume) para restaurar el honor.', 'Huyes', 'Aceptas el castigo físico', 153, 192),
(136, '[Edad: 39 años] Sobreviviste a los mares congelados y ahora comandas un barco pirata moderno en las agitadas aguas del Mar de la China Meridional, buscando objetivos para abordar.', 'Asaltas yates', 'Rabas cargueros', 154, 155),
(137, '[Edad: 39 años] El viejo y sobrecargado barco pesquero colapsa en medio de una tormenta oscura como boca de lobo. Las olas gélidas tragan la cubierta y debes decidir rápido cómo salvar tu vida.', 'Usas bote salvavidas', 'Te aferras a madera', 156, 194),
(138, '[Edad: 41 años] Te conviertes en el mito urbano de los "Hombre Topo". Vives en la red de alcantarillado y túneles de servicio del metro bajo la bulliciosa metrópolis de neón. La oscuridad es tu único amigo.', 'Comes ratas', 'Robas mochilas', 157, 158),
(139, '[Edad: 43 años] El lote de cosméticos "Premium" falsificados que cocinaste en tu sótano ha provocado quemaduras químicas faciales a docenas de personas adineradas. Hay precio sobre tu cabeza.', 'Cambias de nombre', 'Huyes del país', 159, 160),
(140, '[Edad: 43 años] Un error fatal mezclando químicos inestables en tu laboratorio genera una chispa letal. Una bola de fuego aniquila el sótano clandestino.', 'Sobrevives quemado', 'Mueres en llamas', 163, 198),
(141, '[Edad: 46 años] Has declarado una sangrienta y despiadada guerra callejera contra el traidor de tu sindicato. Los tiroteos desde motos y ataques con machetes llenan los noticieros nocturnos.', 'Ganas y dominas', 'Pierdes a tus hombres', 163, 163),
(142, '[Edad: 46 años] Ocultaste tu pasado mafioso huyendo al campo rural, viviendo como un simple cultivador de rábanos. Pero el cacique corrupto del pueblo comienza a extorsionarte exigiendo tributos abusivos.', 'Tragas y pagas (Ruta Buena)', 'Campesinos con hoces (Mala)', 161, 163),
(143, '[Edad: 49 años] Con vendas ensangrentadas y consumiendo medicamentos robados, logras combatir la sepsis de la operación del mercado negro. Eres un cadáver andante impulsado por puro rencor.', 'Vuelves a la calle', 'Buscas venganza', 163, 163),
(144, '[Edad: 51 años] Gracias a tu astucia, te haces con el control de las sombras dentro de los muros de la penitenciaría. Incluso los guardias corruptos te piden permiso para patrullar tus pabellones.', 'Controlas contrabando', 'Organizas motín', 163, 198),
(145, '[Edad: 51 años] El capellán de la prisión logró tocar tu endurecido corazón. Eres puesto en libertad condicional, con el tatuaje de un demonio en tu espalda y la firme intención monástica de no volver a delinquir.', 'Trabajas en un templo', 'Aceptas el último golpe', 161, 146),
(146, '[Edad: 53 años] En tu intento por sobrevivir vendiendo discos piratas y zapatillas falsas en un mercadillo nocturno, un agente de aduanas encubierto te pone las esposas en las muñecas.', 'Sobornas al policía', 'Corres', 163, 163),
(147, '[Edad: 53 años] Limpiando las asquerosas calles como barrendero, descubres en un contenedor oscuro tras un banco un maletín repleto de lingotes de oro no marcados. Nadie te está mirando.', 'Encuentras maletín', 'Sigues trabajando', 163, 161),
(148, '[Edad: 56 años] Usando la basura para extorsionar a políticos corruptos, te elevas como el intocable "Don" de la gestión de residuos. Los alcaldes sudan frío cuando te sientas en sus despachos.', 'Te haces millonario oscuro', 'Te traicionan', 163, 163),
(149, '[Edad: 56 años] Tus quemas nocturnas e ilegales de plásticos tóxicos provocan una nube venenosa sobre un barrio entero, desencadenando una crisis sanitaria nacional sin precedentes.', 'Eludes la ley', 'Te linchan', 163, 192),
(150, '[Edad: 59 años] Tu trampa improvisada en el pasillo vuela por los aires al asesino a sueldo. Entre el humo y los escombros de la explosión masiva, ves su sofisticado equipo intacto.', 'Robas su equipo', 'Desapareces', 163, 163),
(151, '[Edad: 37 años] Tu facción de la Tríada controla ahora tres distritos enteros. El dinero sucio rebosa y debes decidir dónde invertirlo para blanquearlo e institucionalizar tu imperio de violencia.', 'Abres casinos', 'Extorsionas comercios', 163, 163),
(152, '[Edad: 47 años] La guerra de bandas resultó en una emboscada fallida. El jefe enemigo sobrevivió a tu atentado y ha reunido a 50 hombres armados que rodean el edificio donde te escondes.', 'Te escondes', 'Duelo a muerte', 163, 198),
(153, '[Edad: 37 años] Con un pasaporte falso, cruzas la frontera y llegas a los turbios bajos fondos del sudeste asiático, un paraíso sin ley donde tus talentos para la violencia son altamente demandados.', 'Te haces mercenario', 'Vuelves de incógnito', 163, 163),
(154, '[Edad: 40 años] Tu lancha pirata ha interceptado el ostentoso megayate de un oligarca tecnológico en aguas internacionales. Tienes rehenes ricos y la marina patrullera a horas de distancia.', 'Pides rescate', 'Robas joyas', 163, 163),
(155, '[Edad: 40 años] Emboscaste al barco equivocado: era un carguero "cebo" de la patrulla marítima internacional encubierta. Los cañones de agua de alta presión barren tu cubierta sin piedad.', 'Vendes la carga', 'La marina te atrapa', 163, 198),
(156, '[Edad: 40 años] Eres arrastrado a la orilla rocosa de una isla deshabitada del Pacífico, agotado, medio muerto de sed, aferrado a unos tablones roñosos del naufragio.', 'Haces balsa', 'Esperas rescate', 163, 163),
(157, '[Edad: 42 años] Como maestro de las sombras subterráneas, tu empatía residual aflora al encontrar a un grupo de niños huérfanos viviendo en las tuberías huyendo de la dureza de la metrópolis de arriba.', 'Adoptas huérfanos', 'Atacas trenes', 163, 163),
(158, '[Edad: 42 años] Durante tu miseria callejera, arrebatas la mochila de un hombre de traje que cae borracho. Al abrirla, descubres sellos corporativos, drogas de diseño y un disco duro encriptado de la Yakuza.', 'Usas el dinero', 'Devuelves por miedo', 163, 163),
(159, '[Edad: 44 años] Reubicado quirúrgicamente en una nueva ciudad, construyes una compleja red de estafas de ingeniería social (Voice Phishing) imitando a fiscales para desviar fondos de pensionistas.', 'Haces estafas telefónicas', 'Vendes falsificaciones', 163, 163),
(160, '[Edad: 47 años] Escapando de la Interpol, terminas mendigando en las lluviosas calles de una ciudad occidental donde nadie te conoce, comiendo sobras y ocultándote de las cámaras de seguridad.', 'Mafia local te recluta', 'Mendigas', 163, 163),
(161, '[Edad: 62 años] Has alcanzado los míticos 60 años, la edad que completa el ciclo sexagenario cósmico asiático. Organizan un fastuoso "Hwangap / Kanreki" en tu honor, vistiendo las ropas tradicionales de seda.', 'Todos te rinden respeto', 'Tu hijo arruina la fiesta', 165, 162),
(162, '[Edad: 64 años] Tu fortuna material es vasta, pero tus modernos nietos adolescentes, adictos a TikTok, arrugan la nariz al abrazarte quejándose del penetrante olor tradicional al ungüento "Bálsamo de Tigre".', 'Sobornas con Hongbaos', 'Te bañas en perfume caro', 167, 168),
(163, '[Edad: 62 años] Sobreviviste a las guerras de bandas y ahora eres el temido y respetado "Padrino" anciano del distrito. Desde tu despacho, bebes té oscuro moviendo los hilos de los bajos fondos.', 'Lavas dinero con Ramen', 'Operas casinos clandestinos', 169, 170),
(164, '[Edad: 65 años] Tu mente vagabunda, rota por los años en las calles, sufre un brote psicótico grandioso. Te convences plenamente de que eres la reencarnación celestial de un antiguo emperador de la Dinastía Ming.', 'Ordenas construir muralla', 'Exiges tributos en la calle', 163, 163),
(165, '[Edad: 68 años] Disfrutas del dorado amanecer de tu jubilación. Cada mañana a las 6:00 AM, te enfundas en ropas de seda holgadas para practicar la solemne disciplina del Tai Chi con espadas en el parque público.', 'Tai Chi con espadas 6 AM', 'Criticas a jóvenes en internet', 173, 166),
(166, '[Edad: 70 años] Desde tu balcón, ejerces como el viejo gruñón del barrio. Una panda de adolescentes rebosantes de hormonas está contaminando tu paz poniendo estruendoso Trap y Hip-Hop coreano a deshoras.', 'Agua helada desde el balcón', 'Bajas a enseñarles bailes', 175, 176),
(167, '[Edad: 72 años] La tradición choca con la modernidad. Tu nieto favorito anuncia en la cena familiar que abandonará sus estudios de ingeniería robótica para ser "Influencer de viajes virtuales y streamer".', 'Golpe con bastón de bambú', 'Pides que te enseñe VR', 177, 178),
(168, '[Edad: 74 años] Tus días se esfuman en el humo de tabaco de la sala clandestina de Mahjong. Te enfrentas en la partida final contra el invicto campeón del barrio para recuperar el honor de tu pensión.', 'Trampa con ficha en manga', 'Honestidad Zen', 179, 180),
(169, '[Edad: 74 años] El inframundo nunca perdona la edad. Mientras cenas tranquilamente tus fideos en el restaurante, te percatas de que tu "fiel" lugarteniente está intentando envenenar sutilmente tu cuenco de sopa.', 'Disparas bajo la mesa', 'Tu escolta lo acribilla', 181, 182),
(170, '[Edad: 74 años] Una redada masiva y coordinada del escuadrón anticorrupción asalta el lujoso casino VIP subterráneo desde el que manejas tu vasto y longevo imperio criminal.', 'Pasadizo secreto', 'Soborno masivo', 183, 184),
(171, '[Edad: 66 años] El gobierno y los rascacielos sin alma amenazan tu tradicional y centenario barrio de callejones. Las excavadoras de las megacorporaciones se acercan a la puerta de madera de tu amado patio.', 'Resistencia pacífica', 'Huelga de hambre', 183, 183),
(172, '[Edad: 66 años] Amasando una fortuna, decides rendirte al confort supremo de un ático domótico e inteligente en Seúl/Tokio, donde una voz sintetizada y sirvientes robóticos atienden todas tus dolencias físicas.', 'Te hackean la nevera', 'Vives cómodo', 183, 183),
(173, '[Edad: 69 años] El dolor articular y la fatiga te consumen. Recurres a los recónditos saberes de un curandero callejero, que te vende a precio de oro una infusión hervida con caparazón de tortuga negra y ginseng salvaje.', 'Milagro de salud', 'Efecto placebo', 183, 183),
(174, '[Edad: 69 años] La fragilidad de los huesos cede ante el frío metal moderno. Aceptas someterte a una cirugía experimental en el hospital universitario donde brazos robóticos reemplazarán tu cadera desgastada con titanio quirúrgico.', 'Cuerpo de titanio', 'Rechazo del implante', 189, 183),
(175, '[Edad: 71 años] Tus locuras de callejón y tu resistencia inhumana te han convertido en una figura mítica urbana. Hasta las bandas de motoristas locales te saludan con deferencia creyendo que eres un espíritu de la ciudad.', 'Te haces líder del barrio', 'Los ignoras', 183, 183),
(176, '[Edad: 71 años] Intentando avergonzar a los jóvenes en la plaza, demuestras tus anticuados movimientos de baile disco. Inesperadamente, alguien te graba y te conviertes en un meme viral y famoso en toda Asia.', 'Influencer anciano', 'Te rompes la cadera', 183, 183),
(177, '[Edad: 73 años] Las lágrimas de orgullo inundan tus viejos ojos. Tu nieto acepta el peso de la tradición filial y promete graduarse como ingeniero jefe en el conglomerado multinacional, honrando al clan familiar.', 'Te sientes orgulloso', 'Le exiges medicina', 183, 183),
(178, '[Edad: 73 años] Cambiando tu viejo bastón por unas gafas de Realidad Virtual, abrazas el metaverso tecnológico. Te pasas 14 horas al día recorriendo simulaciones de mundos que tus rodillas de 70 años ya no pueden visitar.', 'Viajas por el metaverso', 'Te quedas ciego de las pantallas', 183, 183),
(179, '[Edad: 74 años] La avaricia pudo con la honorabilidad de la vejez. Lograste esconder esa ficha clave bajo la amplia manga de tu Hanfu/Kimono, desplumando los ahorros del campeón local sin que nadie lo notara.', 'Compras regalos', 'Lo guardas todo', 183, 183),
(180, '[Edad: 74 años] Como un verdadero Maestro Zen de las montañas, jugaste con una honestidad inquebrantable. Perdiste todo tu dinero, pero la sonrisa en tu rostro es la de alguien que ha trascendido lo material.', 'Paz interior', 'Sonríes', 183, 183),
(181, '[Edad: 75 años] Sin inmutarte, desenfundaste tu vieja pistola oculta y despachaste al lugarteniente traidor de un tiro limpio frente a todos. La sangre manchó tu sopa, pero tu poder mafioso quedó grabado en piedra para siempre.', 'Consolidas tu imperio oscuro', 'La policía te cerca', 184, 184),
(182, '[Edad: 75 años] La lealtad tiene su recompensa. Diste una señal con la mirada y tus silenciosos guardaespaldas neutralizaron al traidor antes de que desenfundara. Sigues sorbiendo tu té verde caliente plácidamente.', 'Bebes té', 'Ordenas limpiar', 184, 184),
(183, '[Edad: 75 años] Alcanzas los 75 años, la media continental. Estás recostado en la inmaculada cama del hospital, rodeado del monótono pitido de las máquinas médicas de soporte vital. Tu tiempo ha expirado, es hora de dictar tu última voluntad terrenal.', 'Sorbo de té Oolong perfecto', 'Apagad máquinas, gastan luz', 185, 186),
(184, '[Edad: 75 años] A los 75 años, eres el criminal más buscado del continente. Atrapado en la oscura azotea de un rascacielos lloviendo a cántaros, un helicóptero de la Interpol enciende un foco ciego sobre ti. Estás rodeado. No hay juicio pacífico para ti.', 'Saltas a camión de basura', 'Detonas edificio riendo', 187, 188),
(185, '[FINAL BUENO: El Antepasado Venerado] Cierras los ojos en absoluta paz confuciana. En tu fastuoso funeral, cuatro generaciones de descendientes lloran con respeto filial mientras queman millones de billetes falsos, coches y casas de papel maché para asegurar tu lujo en el paraíso espiritual. Te conviertes en la deidad protectora de un linaje inquebrantable.', NULL, NULL, NULL, NULL),
(186, '[FINAL NEUTRAL: El Tacaño Legendario] Dejas de respirar prematuramente y por voluntad propia, solo para ahorrar oxígeno de la máquina y que tus herederos no paguen la factura de la luz médica. Eres velado con simpleza, pero el asombro llega cuando tus nietos descubren millones ocultos en rancios botes de fermentación de Kimchi bajo el suelo.', NULL, NULL, NULL, NULL),
(187, '[FINAL SUPERVIVIENTE: El Rey Basura] La increíble y absurda caída desde la azotea rompe todos los huesos de tu cuerpo, pero el camión de la basura industrial amortigua el golpe. Desapareces de los registros civiles y pasas tus últimos años en libertad salvaje, gobernando un vertedero remoto sobre un ejército de fieros mapaches leales.', NULL, NULL, NULL, NULL),
(188, '[FINAL VILLANO: La Leyenda Oscura] Con una demencial carcajada diabólica que hiela la sangre de los agentes, activas el detonador remoto de tus explosivos. El edificio colapsa. Tu nombre se vuelve una oscura leyenda susurrada en los rincones de Asia. Nadie quemará incienso por ti, pero los niños temblarán al oír tu infame apodo.', NULL, NULL, NULL, NULL),
(189, '[FINAL TECNOLÓGICO: Anciano de Hierro] La operación es un rotundo éxito. Tus huesos de calcio han sido reemplazados por aleaciones cibernéticas de alta tecnología. Con 75 años, corres supermaratones destruyendo el récord del "Hijo de la amiga de tu madre", siendo contratado por el gobierno como inmortal embajador de longevidad.', NULL, NULL, NULL, NULL),
(190, '[GAME OVER: Karoshi (Muerte por exceso de trabajo)] La temible epidemia corporativa te ha alcanzado. Tras encadenar 40 horas ininterrumpidas bajo los fluorescentes y cafeína venenosa, tus arterias ceden. Tu cabeza golpea secamente el teclado del cubículo.', NULL, NULL, NULL, NULL),
(191, '[GAME OVER: Héroe Equivocado] Olvidaste que los cuchillos cortan. En un intento inútil por defender los escasos beneficios diarios de la caja registradora de tu jefe explotador, el atracador no dudó en clavar su acero. Caíste entre estantes de fideos instantáneos.', NULL, NULL, NULL, NULL),
(192, '[GAME OVER: Zapatos de Cemento y Acero] Al Sindicato del Crimen se le agotó la infinita paciencia ante tus constantes excusas e impagos. Tras un "paseo nocturno" en el maletero, tu historia termina en las lodosas y profundas aguas del imponente río Yangtze.', NULL, NULL, NULL, NULL),
(193, '[GAME OVER: Intoxicación por Gutter Oil] La codicia fue tu ruina. Al probar un lote de tu propio pollo frito, frito y refrito en barato y mortífero "Aceite de Alcantarilla" (Gutter oil) ilegal, tu hígado colapsó de manera irreversible y espantosa en menos de 24 horas.', NULL, NULL, NULL, NULL),
(194, '[GAME OVER: El Tifón Asiático] La madre naturaleza impuso su ira sin piedad. Un catastrófico tifón de categoría 5 barrió la costa y aplastó con furia tu precaria e ilegal embarcación pesquera como si fuera una simple cerilla de madera flotante.', NULL, NULL, NULL, NULL),
(195, '[GAME OVER: La Caída del Bambú] En tu desesperada carrera y salto por evadir la ley, calculaste mal. Aterrizaste sobre un andamio de construcción tradicional atado con viejas cuerdas de bambú, que cedió estrepitosamente bajo tu peso proyectándote al vacío de la calle.', NULL, NULL, NULL, NULL),
(196, '[GAME OVER: Cosecha Involuntaria de Órganos] La sepsis que recorría tus venas te dejó completamente incapacitado. El siniestro cirujano del mercado negro del callejón hizo números, sonrió perversamente bajo su mascarilla y dictaminó silenciosamente que eras mucho más rentable vendido a piezas en el extranjero.', NULL, NULL, NULL, NULL),
(197, '[GAME OVER: Tofu Drift Fallido] La obsesión por la puntualidad académica te costó el futuro y la vida. Imprimiendo una velocidad suicida con tu destartalada scooter por las curvas mojadas de la montaña para no llegar tarde al examen, perdiste el control por completo derrapando fatalmente.', NULL, NULL, NULL, NULL),
(198, '[GAME OVER: Lluvia de Plomo Institucional] La hubris nubló tu juicio y creíste tener el poder de un jefe de cartel. Al enfrentarte ciegamente y a punta de pistola a la disciplina marcial de un pelotón táctico de choque SWAT, la respuesta balística de la autoridad fue abrumadora y letal.', NULL, NULL, NULL, NULL),
(199, '[GAME OVER: Taquicardia del Estudiante Exhausto] La obsesión por el éxito académico rompió tus límites biológicos de manera irreversible. Al mezclar en sangre diez latas consecutivas de oscuras bebidas energéticas y té matcha doblemente concentrado, tu castigado corazón de estudiante simplemente estalló en pedazos.', NULL, NULL, NULL, NULL),
(200, '[GAME OVER: El Deshonor Absoluto] Tus pésimos y vergonzosos resultados académicos colmaron el vaso. Humillada, tu familia entera borró tu nombre del árbol genealógico y te desterró al espeso y sombrío bosque de bambú de Sichuan. Allí, desprovisto de habilidades, fuiste brutal y paradójicamente atacado por un oso panda inusualmente territorial.', NULL, NULL, NULL, NULL);
